# Libraries we need
require 'ws2812-plus'
require 'i2c'
require 'lsm6ds3'

# Set up the LED matrix
led = WS2812.new(pin: Board43::GPIO_LEDOUT, num: 256)
led.clear

# How long to pause between frames (in milliseconds)
delay_ms = 100

# Set up the tilt sensor so we can detect upside-down
i2c = I2C.new(
  unit: :RP2040_I2C0,
  sda_pin: Board43::GPIO_IMU_SDA,
  scl_pin: Board43::GPIO_IMU_SCL,
  frequency: 400_000,
)
imu = LSM6DS3.new(i2c)
flip = false

# The picture to show, as a grid of [red, green, blue] colors
pattern = [
  [[255, 255, 255], [255, 255, 255], [255, 255, 255], [255, 255, 255], [255, 255, 255], [255, 255, 255], [255, 255, 255], [255, 255, 255], [255, 255, 255], [255, 255, 255], [252, 252, 252], [145, 174, 114], [92, 137, 39], [92, 146, 42], [117, 109, 55], [90, 23, 3]],
