  [[255, 255, 255], [255, 255, 255], [255, 255, 255], [255, 255, 255], [250, 252, 247], [255, 255, 255], [145, 172, 111], [136, 178, 85], [124, 184, 42], [102, 168, 22], [88, 148, 20], [56, 102, 16], [88, 139, 29], [81, 132, 25], [130, 164, 90], [255, 255, 255]],
