  [[252, 255, 252], [255, 252, 255], [102, 154, 54], [102, 172, 23], [106, 168, 29], [103, 166, 27], [109, 174, 27], [80, 132, 24], [230, 235, 227], [255, 255, 255], [250, 252, 247], [255, 255, 255], [255, 255, 255], [255, 255, 255], [255, 255, 255], [255, 255, 255]],
