  [[180, 136, 102], [71, 13, 0], [191, 150, 117], [255, 255, 255], [255, 252, 255], [255, 255, 255], [255, 255, 255], [255, 255, 255], [255, 255, 255], [255, 255, 255], [255, 255, 255], [255, 255, 255], [255, 255, 255], [255, 255, 255], [255, 255, 255], [255, 255, 255]],
  [[78, 18, 1], [180, 136, 102], [255, 255, 255], [245, 242, 237], [252, 255, 252], [255, 255, 252], [250, 252, 247], [255, 255, 255], [255, 255, 255], [255, 255, 255], [255, 255, 255], [255, 255, 255], [255, 255, 255], [255, 255, 255], [255, 255, 255], [255, 255, 255]],
]

loop do
  # Fade in: gradually brighten from 1/10 up to full brightness
  10.times do |step|
    acc = imu.read_all[:acceleration]
    flip = acc[0] < -0.5 if acc[0].abs > 0.5
    b = step + 1
    16.times do |y|
      dst_y = flip ? 15 - y : y
      16.times do |x|
        dst_x = flip ? 15 - x : x
        c = pattern[y][x]
        led.set_rgb(dst_y * 16 + dst_x, c[0] * b / 10, c[1] * b / 10, c[2] * b / 10)
      end
    end
    led.show
    sleep_ms delay_ms
  end

  # Fade out: dim back toward dark
  10.times do |step|
    acc = imu.read_all[:acceleration]
    flip = acc[0] < -0.5 if acc[0].abs > 0.5
    b = 9 - step
    16.times do |y|
      dst_y = flip ? 15 - y : y
      16.times do |x|
        dst_x = flip ? 15 - x : x
        c = pattern[y][x]
        led.set_rgb(dst_y * 16 + dst_x, c[0] * b / 10, c[1] * b / 10, c[2] * b / 10)
      end
    end
    led.show
    sleep_ms delay_ms
  end

  # Rest in the dark before fading in again
  sleep_ms 1000
end
